\noindent\textbf{[2024 Oct/Nov, 0580/32, Question 7]}\par

\begin{parts}
\item $\mathscr{E} = \{ \text{students in a group} \}$ \\
$M = \{ \text{students who pass the mathematics test} \}$ \\
$S = \{ \text{students who pass the science test} \}$ \\
142 students are in the group. \\
105 students pass the mathematics test. \\
82 students pass the mathematics test and pass the science test. \\
17 students do not pass the mathematics test and do not pass the science test.

\begin{subparts}
    \item Complete the Venn diagram.
    \relinput{Figures/Q07a.tex}
    \Marks{2}

    \item Find $n(M \cup S)$.
    \AnswerLine[][]
    \Marks{1}

    \item One of these students is picked at random. \\
    Find the probability that this student passes the science test but does not pass the mathematics test.
    \AnswerLine[][]
    \Marks{1}
\end{subparts}

\item Use set notation to describe the shaded region.
\relinput{Figures/Q07b.tex}
\AnswerLine[][]
\Marks{1}

\item In a town, the number of students, $n$, who take the science test is 10\,600, correct to the nearest hundred. \\
Complete this statement about the value of $n$.
\AnswerLine[][$\dots \le n < \dots$]
\Marks{2}

\item The table shows the number of students in another town who took the science test in 2022 and 2023.
\relinput{Figures/Q07d.tex}
\begin{center}
\begin{tabular}{|l|c|c|}
\hline
Year               & 2022   & 2023   \\ \hline
Number of students & 15\,800 & 17\,064 \\ \hline
\end{tabular}
\end{center}
Calculate the percentage increase in the number of students from 2022 to 2023.
\AnswerLine[][\%]
\Marks{2}

\item The number of students who took the mathematics test in 2022 is 18\,400. \\
The ratio $\text{number of students who passed} : \text{number of students who did not pass}$ is $4 : 1$. \\
Work out the number of students who passed.
\AnswerLine[][]
\Marks{2}
\end{parts}

